content.m_query_connect_and_combine:
let
    // Step 1: Connect to SharePoint site root
    Source = SharePoint.Files("https://contoso.sharepoint.com/sites/MySite", [ApiVersion=15]),

    // Step 2: Filter to specific library/folder path
    FilteredFiles = Table.SelectRows(Source, each Text.Contains([Folder Path], "/Shared Documents/Reports/")),

    // Step 3: Keep only CSV files
    CSVFilesOnly = Table.SelectRows(FilteredFiles, each [Extension] = ".csv"),

    // Step 4: Add a helper column with parsed CSV content
    AddContent = Table.AddColumn(CSVFilesOnly, "ParsedCSV", each Csv.Document([Content], [Delimiter=",", Columns=null, Encoding=65001, QuoteStyle=QuoteStyle.None])),

    // Step 5: Promote headers in each parsed CSV
    PromoteHeaders = Table.TransformColumns(AddContent, {"ParsedCSV", each Table.PromoteHeaders(_, [PromoteAllScalars=true])}),

    // Step 6: Add source filename column before expanding (useful for month tracking)
    AddFilename = Table.AddColumn(PromoteHeaders, "SourceFile", each [Name]),

    // Step 7: Expand all CSV rows into the main table
    // Replace col1, col2, col3 with actual column names from your CSV headers
    Expanded = Table.ExpandTableColumn(AddFilename, "ParsedCSV", Table.ColumnNames(PromoteHeaders{0}[ParsedCSV]))
in
    Expanded
